import { connectIPC, sendMessage, socketPath } from "../shared/ipc.js";
import type {
  ShellToWorkerMessage,
  WorkerToShellMessage,
  IPCMessage,
} from "../shared/ipc.js";
import { ClaudeBridge } from "./claude-bridge.js";
import type net from "node:net";

const workerId = process.argv[2];
const cwd = process.argv[3] || process.cwd();

if (!workerId) {
  console.error("Worker requires workerId as first argument");
  process.exit(1);
}

let socket: net.Socket;
let bridge: ClaudeBridge;

function send(msg: WorkerToShellMessage): void {
  sendMessage(socket, msg);
}

async function handleMessage(msg: IPCMessage): Promise<void> {
  const m = msg as ShellToWorkerMessage;

  switch (m.type) {
    case "send_prompt":
      await bridge.sendPrompt(m.prompt, m.pins);
      break;

    case "context_reset":
      bridge = createBridge();
      send({ type: "status_update", data: { contextTokens: 0, contextPercent: 0 } });
      break;

    case "shutdown":
      bridge.interrupt();
      socket.end();
      process.exit(0);
      break;

    default:
      send({ type: "error", message: `Unknown message type: ${(m as any).type}`, fatal: false });
  }
}

function createBridge(): ClaudeBridge {
  return new ClaudeBridge(
    {
      onStreamChunk: (content) => send({ type: "stream_chunk", content }),
      onMessageComplete: (role, content, tokens, cost) =>
        send({ type: "message_complete", role, content, tokens, cost }),
      onCompacted: (event) => send({ type: "context_compacted", event }),
      onStatusUpdate: (data) => send({ type: "status_update", data }),
      onError: (message, fatal) => send({ type: "error", message, fatal }),
    },
    { cwd }
  );
}

async function main(): Promise<void> {
  bridge = createBridge();
  const sockPath = socketPath(workerId);

  try {
    socket = await connectIPC(sockPath, handleMessage);
    send({ type: "ready", workerId });
  } catch (err: any) {
    console.error(`Worker ${workerId} failed to connect:`, err.message);
    process.exit(1);
  }
}

main().catch((err) => {
  console.error("Worker fatal:", err);
  process.exit(1);
});
